create or alter view vwPaymentTxns as 
	 select * from (select Id,3 PaymentType, transactionId TransactionReference, '' RetrievalReferenceNumber, terminalserial TerminalSerial, actualtimestamp TransactionTime, internaltxncode InternalTxnCode, IsAllocatedToSale, Account, amount Amount , TxnDocNo, Vtype, narration Narration,'fpl_WemaBankTxns' EntityName, ReservedAt , IsConfirmed from fpl_WemaBankTxns where status = 'Success'  union select Id, mp.PaymentType, mp.TransactionReference, mp.RetrievalReferenceNumber, mp.TerminalSerial, mp.TransactionTime, mp.InternalTxnCode, IsAllocatedToSale, cast(BusinessId as varchar(150)) Account, mp.AmountInLocalCur Amount, TxnDocNo, Vtype, mp.Narration, 'fpl_OnlinePayments' EntityName, ReservedAt , IsConfirmed from fpl_OnlinePayments mp where  ((TransactionType = 'PURCHASE' and TransactionStatus = 'SUCCESSFUL' ) or (TransactionType ='POS_TRANSFER' and  TransactionStatus = 'APPROVED') )    ) dtc

